const ins = $json.data || [];
const campaign = $node['split'].json;
let flagged = [];
let winners = [];
for (const ad of ins) {
  const spend = parseFloat(ad.spend || 0);
  const clicks = parseInt(ad.clicks || 0);
  const leads = (ad.actions || []).find(a => a.action_type === 'lead')?.value || 0;
  const purch = (ad.actions || []).find(a => a.action_type === 'purchase')?.value || 0;
  const rev = (ad.action_values || []).find(a => a.action_type === 'purchase')?.value || 0;
  const cpl = leads > 0 ? spend / parseInt(leads) : null;
  const roas = spend > 0 ? parseFloat(rev) / spend : 0;
  const freq = parseFloat(ad.frequency || 0);
  const ctr = parseFloat(ad.ctr || 0);
  const threshold_cpl = campaign.target_cpl || 50;
  const isUnder = (cpl !== null && cpl > threshold_cpl * 1.5) || (roas > 0 && roas < 1.5) || freq > 3.5 || ctr < 0.7;
  const isWinner = (roas > 3 || (cpl !== null && cpl < threshold_cpl * 0.6)) && spend > 20;
  const row = { ad_id: ad.ad_id, spend, cpl, roas, freq, ctr, leads: parseInt(leads), purchases: parseInt(purch), revenue: parseFloat(rev) };
  if (isUnder) flagged.push(row); else if (isWinner) winners.push(row);
}
return [{ json: { campaign_id: campaign.campaign_id, campaign_name: campaign.campaign_name, client_id: campaign.client_id, flagged, winners, total_ads: ins.length } }];

